/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_enrollment_before_insert` BEFORE INSERT ON `enrollment` FOR EACH ROW BEGIN
    DECLARE v_current INT;
    DECLARE v_max INT;
    DECLARE v_msg    VARCHAR(100);

    SELECT current_students, max_students
    INTO v_current, v_max
    FROM course_offering
    WHERE id = NEW.offering_id;

    IF v_current >= v_max THEN
        SET v_msg = CONCAT('选课已满！当前 ', v_current, '/', v_max);
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = v_msg;
    END IF;
END */;;
DELIMITER ;
