DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_enrollment_after_insert` AFTER INSERT ON `enrollment` FOR EACH ROW BEGIN
    UPDATE course_offering
    SET current_students = current_students + 1
    WHERE id = NEW.offering_id;
END */;;
