/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_enrollment_after_insert_score` AFTER INSERT ON `enrollment` FOR EACH ROW BEGIN
    IF NEW.score IS NOT NULL THEN
        UPDATE student s
        SET weighted_score = (
            SELECT ROUND(SUM(e.score * c.credit) / SUM(c.credit), 2)
            FROM enrollment e
            JOIN course_offering co ON e.offering_id = co.id
            JOIN course c ON co.course_id = c.id
            WHERE e.student_id = NEW.student_id
              AND e.score IS NOT NULL
              AND e.is_deleted = 0
        ), gpa = (
            SELECT ROUND(SUM(c.credit * r.point) / SUM(c.credit), 2)
            FROM enrollment e
            JOIN course_offering co ON e.offering_id = co.id
            JOIN course c ON co.course_id = c.id
            JOIN grade_point_rule r ON e.score BETWEEN r.min_score AND r.max_score
            WHERE e.student_id = NEW.student_id
              AND e.score IS NOT NULL
              AND e.is_deleted = 0
        )
        WHERE s.id = NEW.student_id;
    END IF;
END */;;
DELIMITER ;
