/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_enrollment_after_update` AFTER UPDATE ON `enrollment` FOR EACH ROW BEGIN
    -- 逻辑删除从 0 → 1 时，人数减一
    IF OLD.is_deleted = 0 AND NEW.is_deleted = 1 THEN
        UPDATE course_offering
        SET current_students = current_students - 1
        WHERE id = NEW.offering_id;
    END IF;
END */;;
DELIMITER ;
